using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Preserve EF8 discriminator property name (EF9 default changed to "$type")
            b.HasDiscriminator<string>("Discriminator");

            // Preserve EF8 compound id format "Blog|1" (EF9 default uses key only)
            b.HasRootDiscriminatorInJsonId(true);
        });

        // HasIndex removed — Cosmos DB throws at startup in EF9.
        // Manage indexing via the container's indexing policy instead.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

